      'IVORY','LAYER','LOCUS','MOUND','OCHRE','QUERN','RELIC','SHARD','SHERD','SPADE',
      'STELE','STONE','TOTEM','TRAIL','VAULT','AMULET','BARROW','BEAKER','BRONZE','BURIAL',
      'CHISEL','DATING','DEBRIS','EFFIGY','FIBULA','FRESCO','HEARTH','HELMET','LINTEL','MORTAR',
      'MOSAIC','POLLEN','RITUAL','SCRIPT','SHOVEL','STRATA','STYLUS','TABLET','TEMPLE','TROWEL'
